import {
  _buildQuantizeScaleFromColorPalette as buildQuantizeScaleFromColorPalette,
  _buildThresholdScaleFromRanges as buildThresholdScaleFromRanges,
  type ColorPalette,
  colorPaletteOptions,
} from '@dynatrace/strato-components/charts';

import { buildCategoricalScale } from './build-categorical-scale.js';
import { DEFAULT_RANGE_COLOR } from '../constants.js';
import { createCategoricalColorSchemeFromCustomColorObject } from './create-categorical-color-scheme-from-custom-color-object.js';
import { createCategoricalColorSchemeFromLegendProps } from './create-categorical-color-scheme-from-legend-props.js';
import type {
  CategoricalLegendConfig,
  MapLegendConfig,
  SequentialLegendConfig,
  ThresholdLegendConfig,
} from '../types/legend.js';

export const isThresholdLegend = (
  legendConfig: MapLegendConfig,
): legendConfig is ThresholdLegendConfig => legendConfig.type === 'threshold';

export const isSequentialLegend = (
  legendConfig: MapLegendConfig,
): legendConfig is SequentialLegendConfig => legendConfig.type === 'sequential';

export const isCategoricalLegend = (
  legendConfig: MapLegendConfig,
): legendConfig is CategoricalLegendConfig =>
  legendConfig.type === 'categorical';

/**
 * Builds a scale for the corresponding map legend configuration
 */
export const buildScaleFromLegendConfig = (
  mapLegendConfig: MapLegendConfig,
  categories?: string[],
  dataMax?: number,
) => {
  if (isSequentialLegend(mapLegendConfig)) {
    const { min, max, colorPalette } = mapLegendConfig;
    return buildQuantizeScaleFromColorPalette(min, max, colorPalette);
  } else if (isThresholdLegend(mapLegendConfig)) {
    const { ranges } = mapLegendConfig;
    return buildThresholdScaleFromRanges(ranges, DEFAULT_RANGE_COLOR, {
      max: dataMax,
    });
  } else if (isCategoricalLegend(mapLegendConfig)) {
    const isArrayOfColors = Array.isArray(mapLegendConfig.colorPalette);
    const isDefaultColorPalette = colorPaletteOptions.includes(
      mapLegendConfig.colorPalette as (typeof colorPaletteOptions)[number],
    );
    const isCustomColorObject = !(isDefaultColorPalette || isArrayOfColors);
    const colorPaletteObject = isCustomColorObject
      ? createCategoricalColorSchemeFromCustomColorObject(
          mapLegendConfig.colorPalette as {
            [key: string]: string;
          },
          categories ?? [],
        )
      : createCategoricalColorSchemeFromLegendProps(
          mapLegendConfig.colorPalette as string[] | ColorPalette,
          categories ?? [],
        );

    return buildCategoricalScale(colorPaletteObject);
  }
};
